window.__QUIZ_DATA__=[{"id":"theory>Data Processing>2025>SECTION A>1>a>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Explain the following terms:    data processing;","images":[],"marking_scheme":"Data Processing is the process of collecting, organizing, analyzing, and transforming raw data into meaningful and useful information","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>1>a>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Explain the following terms:  data collation.","images":[],"marking_scheme":"Data Collation is the process of gathering and combining data from different sources into a single, organized format for analysis or reporting.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>1>b","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Describe Data Processing Cycle.","images":[],"marking_scheme":"The Data Processing Cycle is a sequence of steps or phases that raw data goes through to be converted into meaningful, usable information. It's a fundamental concept in information technology and data management, outlining the systematic approach to handling data.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>1>c","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"State four benefits of the computer as a tool for processing data.","images":[],"marking_scheme":"1. Speed \u2013 Computers can process large volumes of data in seconds, much faster than humans.    2. Accuracy \u2013 With correct input, computers provide highly accurate results with minimal errors.    3. Storage \u2013 They can store vast amounts of data in a compact form, making it easy to retrieve and update.    4. Automation \u2013 Computers can automate repetitive tasks like calculations, data entry, and report generation.    5. Efficiency \u2013 They improve productivity by handling multiple tasks quickly and effectively.    6. Security \u2013 Data stored on computers can be protected using passwords, encryption, and backups.    7. Easy Retrieval \u2013 Processed or stored data can be quickly searched and retrieved for use.    8. Consistency \u2013 Results remain consistent when the same operations are performed multiple times.","marks":"4","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION A>2>a>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"FINAL","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:    A;","images":["data:image/jpeg;base64,"],"marking_scheme":"Monitor: This is the screen used to display the visual output of the computer.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>2>a>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"FINAL","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  B;","images":["data:image/jpeg;base64,"],"marking_scheme":"Printer: A device used to produce hard copies of documents or images from the computer.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>2>a>iii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"iii","group":"FINAL","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  C;","images":["data:image/jpeg;base64,"],"marking_scheme":"Mouse: A pointing device used to control the cursor and interact with graphical elements on the screen.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>2>a>iv","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"iv","group":"FINAL","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Figure 1 is a setup of a computer system.  Use the setup to answer questions 2(a) to 2(c) .    Identify the part labelled:  D;","images":["data:image/jpeg;base64,"],"marking_scheme":"Keyboard: An input device used to type data, commands, and control functions into the computer.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>2>b","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"For each device in the setup, tick (\u2713) the box to show if it is an input device or an output device.    DeviceInput DeviceOutput DeviceABCD","images":[],"marking_scheme":"DeviceInput DeviceOutput DeviceA\u2713B\u2713C\u2713D\u2713","marks":"4","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>2>c","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Name two devices that can be used for both input and output operations.","images":[],"marking_scheme":"1. Touchscreen  Input: Detects finger touches/stylus input (e.g., tapping, swiping).  Output: Displays visual feedback (e.g., apps, videos).  Examples: Smartphones, ATMs, interactive kiosks.    2. Network Interface Card (NIC)  Input: Receives data from a network (e.g., downloads).  Output: Sends data to a network (e.g., uploads).  Example: Ethernet/Wi-Fi cards in laptops.    3. Hard Disk Drive (HDD)/Solid State Drive (SSD)  Input: Writes (saves) data to the disk.  Output: Reads (retrieves) data from the disk.  Example: Loading a game (output) and saving progress (input).    4. USB Drive (Flash Drive)  Input: Stores data transferred from a computer.  Output: Provides data to the computer when accessed.    5. Modem  Input: Receives signals from the internet (download).  Output: Sends signals to the internet (upload).    6. Headset with Microphone  Input: Captures audio via the microphone.  Output: Plays sound through the speakers.    7. CD/DVD-RW Drive  Input: Burns (writes) data to discs.  Output: Reads data from discs.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION A>3>a>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"With the aid of well-labelled diagram, explain the following modes of information transmission:    simplex;","images":["data:image/png;base64,"],"marking_scheme":"Simplex mode is a type of communication where data flows in only one direction. One device is the sender, and the other is the receiver. The receiver cannot send data back to the sender.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION A>3>a>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"With the aid of well-labelled diagram, explain the following modes of information transmission:  half duplex;","images":["data:image/png;base64,"],"marking_scheme":"Half duplex communication allows data to flow in both directions, but only one direction at a time. The sender and receiver can both transmit and receive data, but not simultaneously.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION A>3>a>iii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"With the aid of well-labelled diagram, explain the following modes of information transmission:  full duplex.","images":["data:image/png;base64,"],"marking_scheme":"Full-duplex mode is a two-way, simultaneous communication channel. This means that data can flow in both directions between the sender and the receiver at the same time. It's like a two-lane highway where traffic can move in both directions concurrently without interfering with each other.    This mode allows for efficient and continuous exchange of information, as both parties can transmit and receive data independently and without waiting for the other side to finish.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION A>3>b>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"State one example of:    simplex;  mode of information transmission.","images":[],"marking_scheme":"1. Television broadcast \u2013 Information flows from the TV station to your TV only.    2. Radio broadcast \u2013 Sound is transmitted from the radio station to the receiver.    3. Keyboard to computer \u2013 The keyboard only sends signals to the computer.    4. Mouse to computer \u2013 Movement and clicks are only sent from the mouse to the system.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>3>b>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"State one example of:  half duplex;  mode of information transmission.","images":[],"marking_scheme":"1. Walkie-talkies \u2013 Only one person can speak at a time while the other listens.    2. Citizen Band (CB) radios \u2013 Communication happens in both directions, but not simultaneously.    3. Two-way intercom systems \u2013 You must press a button to talk, then release it to listen.    4. Older computer networks using Ethernet hubs \u2013 Data could be sent and received, but not at the same time.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>3>b>iii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"State one example of:  full duplex,  mode of information transmission.","images":[],"marking_scheme":"1. Mobile phone calls \u2013 Both parties can speak and hear each other at the same time.    2. Video conferencing apps (e.g., Zoom, Teams) \u2013 Audio and video are sent and received simultaneously.    3. Modern computer networks using switches \u2013 Devices can send and receive data at the same time.    4. Telephone landlines \u2013 Allow simultaneous two-way communication.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>3>c","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"Name one component of a data communication system.","images":[],"marking_scheme":"1. Sender \u2013 The device or person that initiates the message.    2. Receiver \u2013 The device or person that receives the message.    3. Transmission medium \u2013 The physical path (e.g., cables, air) through which data travels.    4. Message \u2013 The actual data or information being transmitted.    5. Protocol \u2013 The set of rules that govern data communication.    6. Modem \u2013 Converts digital signals to analog and vice versa for transmission over telephone lines.    7. Encoder/Decoder \u2013 Converts data into suitable form for transmission and back to original form at reception.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>4>a","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"ETHICS AND HUMAN ISSUES : SAFETY MEASURES","question":"Differentiate between hackers and spammers.","images":[],"marking_scheme":"Hackers are individuals who gain unauthorized access to computer systems to steal data, disrupt operations, or exploit security weaknesses. Spammers, on the other hand, send unsolicited messages\u2014usually emails\u2014to advertise, spread malware, or scam users. While hackers operate stealthily, spammers are more visible due to the high volume of unwanted messages they send.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>4>b","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"State one importance of add-in in MS Excel.","images":[],"marking_scheme":"1. Data analysis and visualization enhancement \u2013 Add-ins like Power Pivot and Power Map help analyze large data sets and visualize them in 3D maps.    2. Automation of repetitive tasks \u2013 Add-ins can include macros and tools that automate common workflows, saving time.    3. Integration with external databases and applications \u2013 Some add-ins allow Excel to connect with SQL databases or APIs for real-time data.    4. Advanced statistical and mathematical functions \u2013 Tools like the Analysis ToolPak add-in offer regression, histograms, and other advanced features.    5. Custom user-defined functions \u2013 Add-ins let users create and use their own Excel functions not included by default.    6. Improved productivity \u2013 Productivity add-ins add shortcuts, templates, and formatting tools to make work faster.    7. Enhanced charting and graphing \u2013 Some add-ins allow users to create advanced or specialized charts that Excel doesn't natively support.    8. Financial modeling and forecasting \u2013 Add-ins can support scenarios, goal seek, and what-if analysis for budgeting and investment modeling.    9. Real-time data feeds \u2013 Market and financial data add-ins provide constantly updating information inside worksheets.    10. Customization of Excel interface \u2013 Add-ins can add new tabs, buttons, or menus tailored to specific business tasks or user preferences.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>4>c>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"Explain the following terms in computing:    cookies;","images":[],"marking_scheme":"Cookies in computing are small text files stored on a user's computer by a website. They are used to remember information about the user, such as login status, preferences, or items in a shopping cart. When the user revisits the website, the stored cookie data helps provide a more personalized and efficient browsing experience. Cookies can be session-based (temporary) or persistent (saved for future visits).","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>4>c>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"Explain the following terms in computing:  plugin;","images":[],"marking_scheme":"Plugin in computing is a software component that adds specific features or functionalities to an existing computer program or application. It \"plugs in\" to the main software to extend its capabilities without altering the core program. For example, web browsers use plugins to play videos, display PDFs, or block ads. Plugins allow users to customize and enhance their software experience.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION A>4>c>iii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"iii","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : WEB DESIGN PACKAGES","question":"Explain the following terms in computing:  web crawlers.","images":[],"marking_scheme":"Web crawlers are automated programs or bots used by search engines to systematically browse the internet and index web pages. They \"crawl\" from one webpage to another by following links, gathering data about the content, structure, and keywords of websites. This information helps search engines organize and rank pages so users can find relevant results quickly.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION B>5>a","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"a","group":"FINAL","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Figure 2 is an interface of an application software.  Use it to answer questions 5(a) to 5(c).     Identify the type of application whose interface is shown in Figure 2.","images":["data:image/jpeg;base64,"],"marking_scheme":"The type of application shown in Figure 2 is Microsoft PowerPoint, which is a presentation software used to create slideshows for presentations.","marks":"1","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION B>5>b>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Outline the steps to:    insert a new slide to the interface;","images":[],"marking_scheme":"Method 1: Using the Ribbon  1. Open your PowerPoint presentation.  2. Navigate to the slide before where you want the new slide.  3. Go to the Home tab in the ribbon.  4. Click New Slide (or the dropdown arrow to choose a layout).    Method 2: Right-Click (Context Menu)  1. Right-click on a slide thumbnail in the left-side panel.  2. Select New Slide from the menu.    Method 3: Keyboard Shortcut  Windows: Press Ctrl + M.  Mac: Press Cmd + M.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION B>5>b>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Outline the steps to:  delete a slide from the interface.","images":[],"marking_scheme":"1. Open your PowerPoint presentation.    2. In the left pane (slide thumbnail view), click to select the slide you want to delete.    3. Right-click on the selected slide.    4. Choose Delete Slide from the context menu.    Alternatively, after selecting the slide, you can simply press the Delete key on your keyboard to remove it.","marks":"2","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION B>5>c","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"c","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"State two examples of the application in Figure 2.","images":[],"marking_scheme":"1. Microsoft PowerPoint: The most widely used presentation software globally, part of the Microsoft Office suite.    2. Google Slides: A free, web-based presentation program offered as part of Google Workspace, known for its strong collaboration features.    3. Apple Keynote: Apple's presentation software, known for its elegant designs, intuitive interface, and smooth animations, primarily for macOS and iOS users.    4. Prezi: A unique presentation tool that uses a non-linear, zoomable canvas instead of traditional slides, allowing for dynamic and engaging presentations.    5. LibreOffice Impress: A free and open-source presentation program that is part of the LibreOffice suite, offering functionality similar to PowerPoint.","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION B>5>d>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Give two:    uses of the application in Figure 2;","images":[],"marking_scheme":"1. Creating slide presentations for meetings and lectures    2. Designing training materials and tutorials    3. Making business proposals and project reports    4. Preparing visual aids for speeches and seminars    5. Developing marketing and sales presentations","marks":"2","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION B>5>d>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Give two:  differences between transitions and animations in the application shown in Figure 2.","images":[],"marking_scheme":"1. Purpose:  - Transitions control how one slide moves or changes to the next slide during a presentation.  - Animations control the movement or appearance of individual elements (like text, images, or shapes) within a single slide.    2. Scope:  - Transitions apply to the entire slide as it moves to the next.  - Animations apply only to specific objects or content on a slide.    3. Timing:  - Transitions occur between slides.  - Animations happen during the display of a single slide.    4. Types of Effects:  - Transitions include effects like fade, wipe, push, or dissolve between slides.  - Animations include effects like fade in/out, fly in, bounce, or zoom applied to text or objects.    5. User Control:  - Transitions usually trigger when you move to the next slide (manually or automatically).  - Animations can be triggered by clicks, with delays, or in sequence while the slide is displayed.","marks":"6","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION B>5>e>i","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"i","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Highlight the steps to:    run slideshow in the application shown in Figure 2;","images":[],"marking_scheme":"1. Click the \"Slide Show\" tab on the Ribbon at the top of the window.    2. Select \"From Beginning\" to start the slideshow from the first slide, or \"From Current Slide\" to start from the slide you are currently viewing.    3. Alternatively, press the F5 key on the keyboard to start the slideshow from the beginning.    4. You can also press Shift + F5 to start the slideshow from the current slide.    These actions will launch the presentation in full-screen slideshow mode.","marks":"3","difficulty":"1"},{"id":"theory>Data Processing>2025>SECTION B>5>e>ii","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"ii","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Highlight the steps to:  print a handout of 6 slides on a page of the application shown in Figure 2.","images":[],"marking_scheme":"1. Click on the File tab (top-left corner).    2. Select Print from the menu.    3. In the Print settings, click the dropdown under Print Layout or Full Page Slides.    4. Choose Handouts (6 slides per page) from the layout options.    5. Adjust any other print settings as needed (like printer selection, number of copies).    6. Click Print to start printing the handouts.    This will print 6 slides arranged neatly on each page.","marks":"4","difficulty":"2"},{"id":"theory>Data Processing>2025>SECTION B>6>a","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"a","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"You are provided with a list of existing contacts in a database. Describe in detail, the step-by-step approach to:    create;  a mail merge using a template in MS Word.","images":[],"marking_scheme":"(i) Prepare the contact list in Excel with clear column headers (e.g., First Name, Last Name, Email).    (ii) Open Microsoft Word.    (iii) Open the mail merge template document you want to use. If none exists, create a new blank document and format it as needed.    (iv) Click the Mailings tab on the Ribbon.    (v) Click Start Mail Merge and select the document type (e.g., Letters, Labels, Envelopes).    (vi) Click Select Recipients and choose Use an Existing List.    (vii) Browse to locate and select your existing contacts database (e.g., an Excel file).    (viii) If prompted, select the worksheet or table that contains your contact list and confirm the data range.    (ix) Place the cursor in the document where personalized data should appear.    (x) Click Insert Merge Field and select the fields (e.g., First_Name, Last_Name, Address) to insert them in the appropriate places.    (xi) Repeat as needed for all fields you want to personalize.    (xii) Format the document, adjusting fonts, spacing, and layout around the merge fields to ensure a professional look.    (xiii) Save the main mail merge document to preserve the setup for later use.","marks":"17","difficulty":"3"},{"id":"theory>Data Processing>2025>SECTION B>6>b","subject":"Data Processing","year":"2025","type":"Theory","sub_label":"b","group":"","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"You are provided with a list of existing contacts in a database. Describe in detail, the step-by-step approach to:  preview and complete,  a mail merge using a template in MS Word.","images":[],"marking_scheme":"(i) With the mail merge document open, go to the Mailings tab.    (ii) Click Preview Results to see how the merged data populates the fields.    (iii) Use the left and right arrow buttons next to Preview Results to scroll through individual records for verification.    (iv) If you find any errors, make corrections to the main document or update the recipient list as needed.    (v) Once satisfied, click Finish & Merge.    (vi) Choose one of the following options:  - Edit Individual Documents to generate a new document containing all merged letters for final review or printing;  - Print Documents to send the merged documents directly to a printer;  - Send E-mail Messages if merging emails.    (vii) If you select Edit Individual Documents, specify whether to merge all records or a range, then click OK.    (viii) Save the merged document if you edited or created individual files.    (ix) Close the mail merge main document when finished.    (x) It is recommended to back up the original contact list and any merged documents to prevent data loss.","marks":"3","difficulty":"3"}];